class Solution{
function bellmanFord(V, edges, S) {
    // Initialize distance array with a large number (Infinity approximation)
const dist = new Array(V).fill(1e8);
dist[S] = 0;  // Distance to source is 0

    // Relax all edges V-1 times
    for (let i = 0; i < V - 1; i++) {
        for (const [u, v, wt] of edges) {  //Starting point of the edge
            if (dist[u] !== 1e8 && dist[u] + wt < dist[v]) { //V is the ending point of the edge
                dist[v] = dist[u] + wt;  //Wt is the edge weight
            }
        }
    }

    // Check for negative weight cycle
    for (const [u, v, wt] of edges) {
        if (dist[u] !== 1e8 && dist[u] + wt < dist[v]) {
            return [-1]; // Negative weight cycle detected
        }
    }

    return dist;
}

